import numpy as np

def search(query, df, bm25, model, index, top_k=10):
    query_terms = query.lower().split()

    # Get top candidates from both methods
    bm25_scores = bm25.get_scores(query_terms)
    bm25_idx = np.argsort(bm25_scores)[::-1][:100]

    query_vec = model.encode([query])
    distances, vec_idx = index.search(query_vec.astype("float32"), 100)

    # RRF calculation
    ranks = {}
    for i, idx in enumerate(bm25_idx):
        ranks[idx] = ranks.get(idx, 0) + 1.0 / (60 + i)
    for i, idx in enumerate(vec_idx[0]):
        ranks[idx] = ranks.get(idx, 0) + 1.0 / (60 + i)

    sorted_idx = sorted(ranks, key=ranks.get, reverse=True)[:top_k]
    return df.iloc[sorted_idx][["title", "overview"]].to_dict("records")

